/**
 * This object contains helper methods for generating a [RasterColormapRenderer](https://developers.arcgis.com/javascript/latest/references/core/renderers/RasterColormapRenderer/) for raster layers (i.e. [ImageryLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/ImageryLayer/), [ImageryTileLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/ImageryTileLayer/)).
 *
 * The [createRenderer()](https://developers.arcgis.com/javascript/latest/references/core/smartMapping/raster/renderers/colormap/#createRenderer) method in this module generates a renderer that may be applied directly to the input layer.
 *
 * @since 4.20
 */
import type RasterColormapRenderer from "../../../renderers/RasterColormapRenderer.js";
import type { RasterRendererParameters } from "./types.js";

/**
 * The result object of the [createRenderer()](https://developers.arcgis.com/javascript/latest/references/core/smartMapping/raster/renderers/colormap/#createRenderer) method. See the table
 * below for details of each property.
 */
export interface RasterColormapResult {
  /**
   * The colormap renderer to apply
   *   to the input layer.
   */
  renderer: RasterColormapRenderer;
}

/**
 * Generates a [RasterColormapRenderer](https://developers.arcgis.com/javascript/latest/references/core/renderers/RasterColormapRenderer/) used to render imagery data.
 *
 * @param parameters - Input parameters for generating a colormap visualization.
 * @returns Resolves to
 *   an object containing a RasterColormapRenderer that can be set on the input layer.
 */
export function createRenderer(parameters: RasterRendererParameters): Promise<RasterColormapResult>;